import { Router } from 'express';
import { authenticate, requireRoles } from '../middleware/auth.js';
import * as c from '../controllers/adminController.js';
const r = Router();
r.use(authenticate, requireRoles('SUPER_ADMIN'));
r.get('/users', c.users);
r.get('/users/:id', c.userDetail);
r.post('/users/:id/impersonate', c.impersonateUser);
r.patch('/users/:id/status', c.setStatus);
r.delete('/users/:id', c.deleteUser);
r.get('/analytics', c.analytics);
export default r;
